import React, { useState } from 'react';
import './LoginForm.css';
import { FaUser, FaLock } from "react-icons/fa";

const LoginForm = () => {
  // 1. Kullanıcının girdiklerini tutacağımız değişkenler (State'ler)
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // 2. Form Login modunda mı yoksa Register modunda mı onu takip ediyoruz
  const [isRegistering, setIsRegistering] = useState(false); 

  // 3. Butona tıklandığında çalışacak fonksiyon
  const handleSubmit = async (e) => {
    e.preventDefault(); // Sayfanın yenilenmesini engeller

    if (isRegistering) {
        // REGISTER MODUNDAYSA BACKEND'E İSTEK AT
        try {
            const response = await fetch('http://localhost:5000/api/auth/register', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                // State'deki e-posta ve şifreyi JSON formatına çevirip gönderiyoruz
                body: JSON.stringify({ email, password }), 
            });

            const data = await response.json();

            if (response.ok) {
                alert("Kayıt Başarılı: " + data.message);
                // Başarılı olursa login ekranına geri döndürebiliriz
                setIsRegistering(false); 
            } else {
                alert("Hata: " + data.message);
            }
        } catch (error) {
            console.error("Bağlantı hatası:", error);
            alert("Sunucuya bağlanılamadı. Backend açık mı?");
        }
    } else {
        // LOGIN MODUNDAYSA (Bunu bir sonraki adımda yazacağız)
        alert("Login backend'ini henüz yazmadık kral! Önce 'Register' diyerek bir kayıt oluşturalım.");
    }
  };

  return (
    <div className='wrapper'> 
      {/* Form gönderildiğinde handleSubmit fonksiyonunu tetikliyoruz */}
      <form onSubmit={handleSubmit}>
        <h1>{isRegistering ? "Register" : "Login"}</h1>

        <div className="input-box">
            <input 
              type="email" // "mail" yerine doğrusu olan "email" yaptık
              placeholder='E-Mail' 
              required 
              value={email} // Input'u state'e bağladık
              onChange={(e) => setEmail(e.target.value)} // Yazdıkça state güncelleniyor
            />
            <FaUser className='icon' />
        </div>

        <div className="input-box">
            <input 
              type="password" 
              placeholder='Password' 
              required 
              value={password} // Input'u state'e bağladık
              onChange={(e) => setPassword(e.target.value)} // Yazdıkça state güncelleniyor
            />
            <FaLock className='icon' />
        </div>

        {/* Register modundayken Beni Hatırla ve Şifremi Unuttum mantıksız olacağı için gizliyoruz */}
        {!isRegistering && (
            <div className="remember-forgot">
                <label><input type="checkbox" />Remember me</label>
                <a href="#">Forgot Password?</a>
            </div>
        )}

        <button type="submit">{isRegistering ? "REGISTER" : "LOGIN"}</button>

        <div className="register-link">
            <p>
                {isRegistering ? "Already have an account? " : "Don't Have an Account? "}
                <a href="#" onClick={(e) => {
                    e.preventDefault();
                    setIsRegistering(!isRegistering); // Login ve Register modları arasında geçiş yapar
                }}>
                    {isRegistering ? "Login" : "Register"}
                </a>
            </p>
        </div>
      </form>
    </div>
  );
};

export default LoginForm;
